#include "sda_exact_linf.h"
#include <stdlib.h>
#include <time.h>
static long labs2(long x){return x<0?-x:x;} static long maxl(long a,long b){return a>b?a:b;}
static long norm(const long*B,size_t d,const long*x,long*v){ long m=0; for(size_t i=0;i<d;i++){ long s=0; for(size_t j=i;j<d;j++) s+=B[i*d+j]*x[j]; if(v)v[i]=s; m=maxl(m,labs2(s)); } return m; }
static void rec(const long*B,size_t d,int l,long*x,long R,sda_linf_stats*st){ st->nodes_visited++; if(l<0){ int nz=0; for(size_t i=0;i<d;i++) nz|=(x[i]!=0); if(!nz)return; st->leaves_visited++; long v[8]={0}; long nm=norm(B,d,x,v); if(nm<st->best_norm){st->best_norm=nm;st->final_radius=nm; for(size_t i=0;i<d;i++){st->best_coefficients[i]=x[i];st->best_vector[i]=v[i];}} return;} long high=0; for(size_t j=(size_t)l+1;j<d;j++) high+=B[l*d+j]*x[j]; long b=B[l*d+l]; if(b==0)return; long lo=-R-labs2(high), hi=R+labs2(high); for(long xi=lo;xi<=hi;xi++){ long e=labs2(high+b*xi); if(e<=R) {x[l]=xi; rec(B,d,l-1,x,st->best_norm?st->best_norm:R,st);} else st->branches_pruned++; if(xi==hi)break; } x[l]=0; }
int sda_exact_linf_solve(const long*B,size_t d,sda_linf_stats*st){ if(!B||!st||d==0||d>8)return-1; for(size_t i=0;i<d;i++){ for(size_t j=0;j<i;j++) if(B[i*d+j])return-1; if(!B[i*d+i])return-1;} clock_t a=clock(); for(size_t i=0;i<sizeof*st/sizeof(long);i++); *st=(sda_linf_stats){0}; st->initial_radius=64; st->best_norm=st->initial_radius; long x[8]={0}; rec(B,d,(int)d-1,x,st->initial_radius,st); st->elapsed_time=(double)(clock()-a)/CLOCKS_PER_SEC; return 0; }
long sda_linf_bruteforce(const long*B,size_t d,int bound){ long best=1L<<30,x[8]={0},v[8]; unsigned long total=1; for(size_t i=0;i<d;i++) total*= (unsigned)(2*bound+1); for(unsigned long n=0;n<total;n++){ unsigned long t=n; int nz=0; for(size_t i=0;i<d;i++){ x[i]=(long)(t%(2*bound+1))-bound; t/=2*bound+1; nz|=x[i]!=0;} if(!nz)continue; long nm=norm(B,d,x,v); if(nm<best)best=nm;} return best; }
